{"version":3,"sources":["../../../../app/attendance/page.tsx","../../../../hooks/useAttendance.ts","../../../../components/attendance/StatCards.tsx","../../../../components/attendance/FilterBar.tsx","../../../../components/attendance/StatusBadge.tsx","../../../../components/attendance/AttendanceTable.tsx","../../../../components/attendance/AddEmployeeModal.tsx","../../../../components/attendance/EditRecordModal.tsx","../../../../components/attendance/DeleteConfirmModal.tsx"],"sourcesContent":["\"use client\";\n\nimport { useState } from \"react\";\nimport { useAttendance } from \"@/hooks/useAttendance\";\nimport { StatCards } from \"@/components/attendance/StatCards\";\nimport { FilterBar } from \"@/components/attendance/FilterBar\";\nimport { AttendanceTable } from \"@/components/attendance/AttendanceTable\";\nimport { AddEmployeeModal } from \"@/components/attendance/AddEmployeeModal\";\nimport { EditRecordModal } from \"@/components/attendance/EditRecordModal\";\nimport { DeleteConfirmModal } from \"@/components/attendance/DeleteConfirmModal\";\nimport type { AttendanceRecord } from \"@/types/attendance\";\n\nexport default function AttendancePage() {\n  const {\n    records,\n    summary,\n    filter,\n    updateFilter,\n    syncing,\n    syncedAt,\n    error,\n    page,\n    totalPages,\n    totalFiltered,\n    setPage,\n    sync,\n    markLeave,\n    addEmployee,\n    editRecord,\n    deleteRecord,\n  } = useAttendance();\n\n  const [isAddOpen, setIsAddOpen] = useState(false);\n  const [editTarget, setEditTarget] = useState<AttendanceRecord | null>(null);\n  const [deleteTarget, setDeleteTarget] = useState<AttendanceRecord | null>(null);\n\n  return (\n    <div className=\"min-h-screen bg-gray-50\">\n      {/* Top bar */}\n      <div className=\"bg-gray-900 px-6 py-4 flex items-center justify-between\">\n        <div>\n          <h1 className=\"text-white text-lg font-medium\">Student Attendance</h1>\n          <p className=\"text-gray-400 text-sm mt-0.5\">\n            Biometric attendance via SmartOffice API\n          </p>\n        </div>\n        <div className=\"flex items-center gap-3\">\n          <button\n            onClick={() => sync(filter.date)}\n            disabled={syncing}\n            className=\"flex items-center gap-2 px-4 py-2 text-sm font-medium bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-60 transition-colors\"\n          >\n            <svg className={`w-4 h-4 ${syncing ? \"animate-spin\" : \"\"}`} fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n              <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15\"/>\n            </svg>\n            {syncing ? \"Syncing...\" : \"Sync Biometric\"}\n          </button>\n          <button\n            onClick={() => setIsAddOpen(true)}\n            className=\"flex items-center gap-2 px-4 py-2 text-sm font-medium bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors\"\n          >\n            <svg className=\"w-4 h-4\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n              <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M12 4v16m8-8H4\"/>\n            </svg>\n            Add Employee\n          </button>\n          <button className=\"flex items-center gap-2 px-4 py-2 text-sm font-medium bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors\">\n            <svg className=\"w-4 h-4\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n              <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4\"/>\n            </svg>\n            Export Excel\n          </button>\n        </div>\n      </div>\n\n      {/* Error banner */}\n      {error && (\n        <div className=\"mx-6 mt-4 px-4 py-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-3 text-sm text-red-700\">\n          <svg className=\"w-4 h-4 flex-shrink-0\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n            <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M12 9v2m0 4h.01M12 3C6.48 3 2 7.48 2 12s4.48 9 10 9 10-4.48 10-10S17.52 3 12 3z\"/>\n          </svg>\n          <span>\n            <strong>Sync error:</strong> {error}.{\" \"}\n            {error.includes(\"API Key\") && \"Check your SMARTOFFICE_API_KEY in .env.local.\"}\n            {error.includes(\"Serial Number\") && \"Verify the device serial number in SmartOffice.\"}\n          </span>\n        </div>\n      )}\n\n      {/* Stat cards */}\n      <StatCards summary={summary} />\n\n      {/* Table card */}\n      <div className=\"mx-6 mb-6 bg-white rounded-xl border border-gray-200 overflow-hidden\">\n        {/* Table header */}\n        <div className=\"bg-gray-900 px-5 py-3.5 flex items-center justify-between\">\n          <h2 className=\"text-white text-sm font-medium flex items-center gap-2\">\n            <svg className=\"w-4 h-4\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n              <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\"/>\n            </svg>\n            Attendance Records\n          </h2>\n\n          {/* Legend */}\n          <div className=\"flex items-center gap-4 text-xs text-gray-400\">\n            {[\n              { color: \"bg-green-500\",  label: \"Present\"  },\n              { color: \"bg-red-500\",    label: \"Absent\"   },\n              { color: \"bg-amber-500\",  label: \"Late\"     },\n              { color: \"bg-indigo-500\", label: \"On Leave\" },\n            ].map(({ color, label }) => (\n              <span key={label} className=\"flex items-center gap-1.5\">\n                <span className={`w-2 h-2 rounded-full ${color}`} />\n                {label}\n              </span>\n            ))}\n          </div>\n        </div>\n\n        <FilterBar\n          filter={filter}\n          onChange={updateFilter}\n          onSync={() => sync(filter.date)}\n          syncing={syncing}\n          syncedAt={syncedAt}\n        />\n\n        <AttendanceTable\n          records={records}\n          page={page}\n          totalPages={totalPages}\n          totalFiltered={totalFiltered}\n          onPageChange={setPage}\n          onMarkLeave={markLeave}\n          onEdit={setEditTarget}\n          onDelete={setDeleteTarget}\n        />\n      </div>\n\n      {/* Modals */}\n      <AddEmployeeModal\n        open={isAddOpen}\n        onClose={() => setIsAddOpen(false)}\n        onSubmit={addEmployee}\n      />\n      <EditRecordModal\n        open={!!editTarget}\n        record={editTarget}\n        onClose={() => setEditTarget(null)}\n        onSubmit={editRecord}\n      />\n      <DeleteConfirmModal\n        open={!!deleteTarget}\n        record={deleteTarget}\n        onClose={() => setDeleteTarget(null)}\n        onConfirm={deleteRecord}\n      />\n    </div>\n  );\n}\n","\"use client\";\n\nimport { useState, useCallback, useMemo } from \"react\";\nimport type {\n  AttendanceRecord,\n  AttendanceSummary,\n  AttendanceStatus,\n  FilterState,\n} from \"@/types/attendance\";\n\nconst today = new Date().toISOString().split(\"T\")[0];\n\nconst defaultFilter: FilterState = {\n  search: \"\",\n  status: \"\",\n  date: today,\n};\n\n// ── Static student records ──────────────────────────────────────────\nconst staticRecords: AttendanceRecord[] = [\n  {\n    student: { id: \"1\", code: \"STU001\", name: \"Aarav Sharma\", gender: \"Male\", contact: \"9876543210\", rollNo: \"01\", standard: \"10A\" },\n    date: today, punchIn: \"08:05:32\", punchOut: \"14:30:10\", serialNumber: \"DEV-001\", status: \"Present\", temperature: 36.5, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"2\", code: \"STU002\", name: \"Priya Patel\", gender: \"Female\", contact: \"9876543211\", rollNo: \"02\", standard: \"10A\" },\n    date: today, punchIn: \"08:45:11\", punchOut: \"14:28:55\", serialNumber: \"DEV-001\", status: \"Late\", temperature: 36.7, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"3\", code: \"STU003\", name: \"Rohan Mehta\", gender: \"Male\", contact: \"9876543212\", rollNo: \"03\", standard: \"10A\" },\n    date: today, punchIn: null, punchOut: null, serialNumber: \"DEV-001\", status: \"Absent\", logCount: 0,\n  },\n  {\n    student: { id: \"4\", code: \"STU004\", name: \"Ananya Gupta\", gender: \"Female\", contact: \"9876543213\", rollNo: \"04\", standard: \"10A\" },\n    date: today, punchIn: \"07:55:20\", punchOut: \"14:35:42\", serialNumber: \"DEV-001\", status: \"Present\", temperature: 36.4, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"5\", code: \"STU005\", name: \"Vihaan Singh\", gender: \"Male\", contact: \"9876543214\", rollNo: \"05\", standard: \"10A\" },\n    date: today, punchIn: null, punchOut: null, serialNumber: \"DEV-001\", status: \"On Leave\", logCount: 0,\n  },\n  {\n    student: { id: \"6\", code: \"STU006\", name: \"Diya Reddy\", gender: \"Female\", contact: \"9876543215\", rollNo: \"06\", standard: \"10A\" },\n    date: today, punchIn: \"08:02:17\", punchOut: \"14:29:03\", serialNumber: \"DEV-001\", status: \"Present\", temperature: 36.6, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"7\", code: \"STU007\", name: \"Arjun Nair\", gender: \"Male\", contact: \"9876543216\", rollNo: \"07\", standard: \"10A\" },\n    date: today, punchIn: \"09:10:44\", punchOut: \"14:32:18\", serialNumber: \"DEV-001\", status: \"Late\", temperature: 36.8, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"8\", code: \"STU008\", name: \"Ishita Verma\", gender: \"Female\", contact: \"9876543217\", rollNo: \"08\", standard: \"10A\" },\n    date: today, punchIn: \"08:00:05\", punchOut: \"14:25:33\", serialNumber: \"DEV-001\", status: \"Present\", temperature: 36.3, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"9\", code: \"STU009\", name: \"Kabir Joshi\", gender: \"Male\", contact: \"9876543218\", rollNo: \"09\", standard: \"10A\" },\n    date: today, punchIn: null, punchOut: null, serialNumber: \"DEV-001\", status: \"Absent\", logCount: 0,\n  },\n  {\n    student: { id: \"10\", code: \"STU010\", name: \"Myra Khan\", gender: \"Female\", contact: \"9876543219\", rollNo: \"10\", standard: \"10A\" },\n    date: today, punchIn: \"07:58:29\", punchOut: \"14:31:47\", serialNumber: \"DEV-001\", status: \"Present\", temperature: 36.5, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"11\", code: \"STU011\", name: \"Reyansh Chopra\", gender: \"Male\", contact: \"9876543220\", rollNo: \"11\", standard: \"10A\" },\n    date: today, punchIn: \"08:03:55\", punchOut: \"14:27:12\", serialNumber: \"DEV-001\", status: \"Present\", temperature: 36.4, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"12\", code: \"STU012\", name: \"Sara Ali\", gender: \"Female\", contact: \"9876543221\", rollNo: \"12\", standard: \"10A\" },\n    date: today, punchIn: null, punchOut: null, serialNumber: \"DEV-001\", status: \"On Leave\", logCount: 0,\n  },\n  {\n    student: { id: \"13\", code: \"STU013\", name: \"Aditya Kumar\", gender: \"Male\", contact: \"9876543222\", rollNo: \"13\", standard: \"10A\" },\n    date: today, punchIn: \"08:50:30\", punchOut: \"14:33:05\", serialNumber: \"DEV-001\", status: \"Late\", temperature: 36.9, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"14\", code: \"STU014\", name: \"Navya Iyer\", gender: \"Female\", contact: \"9876543223\", rollNo: \"14\", standard: \"10A\" },\n    date: today, punchIn: \"07:50:12\", punchOut: \"14:34:28\", serialNumber: \"DEV-001\", status: \"Present\", temperature: 36.2, temperatureState: \"Normal\", logCount: 2,\n  },\n  {\n    student: { id: \"15\", code: \"STU015\", name: \"Vivaan Desai\", gender: \"Male\", contact: \"9876543224\", rollNo: \"15\", standard: \"10A\" },\n    date: today, punchIn: null, punchOut: null, serialNumber: \"DEV-001\", status: \"Absent\", logCount: 0,\n  },\n];\n\nlet nextId = 16;\n\nfunction computeSummary(recs: AttendanceRecord[]): AttendanceSummary {\n  return {\n    total: recs.length,\n    present: recs.filter((r) => r.status === \"Present\").length,\n    absent: recs.filter((r) => r.status === \"Absent\").length,\n    late: recs.filter((r) => r.status === \"Late\").length,\n    onLeave: recs.filter((r) => r.status === \"On Leave\").length,\n  };\n}\n\nexport interface AddEmployeeData {\n  name: string;\n  gender: string;\n  contact: string;\n  rollNo: string;\n  standard: string;\n  status: AttendanceStatus;\n  punchIn: string;\n  punchOut: string;\n}\n\nexport interface EditRecordData {\n  name: string;\n  contact: string;\n  status: AttendanceStatus;\n  punchIn: string;\n  punchOut: string;\n}\n\nexport function useAttendance() {\n  const [records, setRecords] = useState<AttendanceRecord[]>(staticRecords);\n  const [filter, setFilter] = useState<FilterState>(defaultFilter);\n  const [syncing] = useState(false);\n  const [syncedAt] = useState<string | null>(new Date().toISOString());\n  const [error] = useState<string | null>(null);\n  const [page, setPage] = useState(0);\n\n  const PER_PAGE = 10;\n\n  // Sync is a no-op with static data\n  const sync = useCallback(async (_date?: string) => {\n    // No-op: data is static\n  }, []);\n\n  const markLeave = useCallback(async (studentCode: string) => {\n    setRecords((prev) =>\n      prev.map((r) =>\n        r.student.code === studentCode\n          ? { ...r, status: \"On Leave\" as const }\n          : r\n      )\n    );\n  }, []);\n\n  // ── Add Employee ──────────────────────────────────────────────────\n  const addEmployee = useCallback((data: AddEmployeeData) => {\n    const id = String(nextId++);\n    const code = `STU${id.padStart(3, \"0\")}`;\n\n    const newRecord: AttendanceRecord = {\n      student: {\n        id,\n        code,\n        name: data.name,\n        gender: data.gender,\n        contact: data.contact,\n        rollNo: data.rollNo,\n        standard: data.standard,\n      },\n      date: today,\n      punchIn: data.punchIn || null,\n      punchOut: data.punchOut || null,\n      serialNumber: \"DEV-001\",\n      status: data.status,\n      logCount: data.punchIn ? (data.punchOut ? 2 : 1) : 0,\n    };\n\n    setRecords((prev) => [newRecord, ...prev]);\n    setPage(0);\n  }, []);\n\n  // ── Edit Record ───────────────────────────────────────────────────\n  const editRecord = useCallback((studentCode: string, data: EditRecordData) => {\n    setRecords((prev) =>\n      prev.map((r) =>\n        r.student.code === studentCode\n          ? {\n              ...r,\n              student: { ...r.student, name: data.name, contact: data.contact },\n              status: data.status,\n              punchIn: data.punchIn || null,\n              punchOut: data.punchOut || null,\n              logCount: data.punchIn ? (data.punchOut ? 2 : 1) : 0,\n            }\n          : r\n      )\n    );\n  }, []);\n\n  // ── Delete Record ─────────────────────────────────────────────────\n  const deleteRecord = useCallback((studentCode: string) => {\n    setRecords((prev) => prev.filter((r) => r.student.code !== studentCode));\n  }, []);\n\n  const updateFilter = useCallback((patch: Partial<FilterState>) => {\n    setFilter((prev) => ({ ...prev, ...patch }));\n    setPage(0);\n  }, []);\n\n  const filtered = useMemo(() => {\n    const q = filter.search.toLowerCase();\n    return records.filter((r) => {\n      const matchSearch =\n        !q ||\n        r.student.name.toLowerCase().includes(q) ||\n        r.student.contact.includes(q) ||\n        r.student.code.includes(q);\n\n      const matchStatus = !filter.status || r.status === filter.status;\n\n      return matchSearch && matchStatus;\n    });\n  }, [records, filter.search, filter.status]);\n\n  const filteredSummary = useMemo(() => computeSummary(filtered), [filtered]);\n\n  const totalPages = Math.ceil(filtered.length / PER_PAGE);\n  const paged = filtered.slice(page * PER_PAGE, (page + 1) * PER_PAGE);\n\n  return {\n    records: paged,\n    allRecords: records,\n    summary: filteredSummary,\n    filter,\n    updateFilter,\n    syncing,\n    syncedAt,\n    error,\n    page,\n    totalPages,\n    totalFiltered: filtered.length,\n    setPage,\n    sync,\n    markLeave,\n    addEmployee,\n    editRecord,\n    deleteRecord,\n  };\n}\n","\"use client\";\n\nimport type { AttendanceSummary } from \"@/types/attendance\";\n\ninterface Props {\n  summary: AttendanceSummary;\n}\n\nconst CARDS = [\n  {\n    key: \"total\" as const,\n    label: \"Total Students\",\n    bg: \"bg-blue-600\",\n    icon: (\n      <svg className=\"w-6 h-6 opacity-80\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n        <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M17 20h5v-2a4 4 0 00-4-4h-1M9 20H4v-2a4 4 0 014-4h1m4 6v-2m0 0a4 4 0 10-4-4 4 4 0 004 4z\"/>\n      </svg>\n    ),\n  },\n  {\n    key: \"present\" as const,\n    label: \"Present Today\",\n    bg: \"bg-green-600\",\n    icon: (\n      <svg className=\"w-6 h-6 opacity-80\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n        <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z\"/>\n      </svg>\n    ),\n  },\n  {\n    key: \"absent\" as const,\n    label: \"Absent Today\",\n    bg: \"bg-orange-600\",\n    icon: (\n      <svg className=\"w-6 h-6 opacity-80\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n        <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z\"/>\n      </svg>\n    ),\n  },\n  {\n    key: \"late\" as const,\n    label: \"Late / On Leave\",\n    bg: \"bg-indigo-600\",\n    icon: (\n      <svg className=\"w-6 h-6 opacity-80\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n        <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z\"/>\n      </svg>\n    ),\n  },\n];\n\nexport function StatCards({ summary }: Props) {\n  const getValue = (key: keyof AttendanceSummary) => {\n    if (key === \"late\") return summary.late + summary.onLeave;\n    return summary[key];\n  };\n\n  return (\n    <div className=\"grid grid-cols-2 lg:grid-cols-4 gap-4 p-6\">\n      {CARDS.map(({ key, label, bg, icon }) => (\n        <div key={key} className={`${bg} text-white rounded-xl p-5 flex flex-col gap-2`}>\n          <div>{icon}</div>\n          <p className=\"text-sm opacity-90\">{label}</p>\n          <p className=\"text-3xl font-medium tabular-nums\">{getValue(key)}</p>\n        </div>\n      ))}\n    </div>\n  );\n}\n","\"use client\";\n\nimport { useState, useEffect } from \"react\";\nimport type { FilterState, AttendanceStatus } from \"@/types/attendance\";\n\ninterface Props {\n  filter: FilterState;\n  onChange: (patch: Partial<FilterState>) => void;\n  onSync: () => void;\n  syncing: boolean;\n  syncedAt: string | null;\n}\n\nconst STATUS_OPTIONS: { value: AttendanceStatus | \"\"; label: string }[] = [\n  { value: \"\", label: \"All Status\" },\n  { value: \"Present\", label: \"Present\" },\n  { value: \"Absent\", label: \"Absent\" },\n  { value: \"Late\", label: \"Late\" },\n  { value: \"On Leave\", label: \"On Leave\" },\n];\n\nfunction formatSyncTime(iso: string) {\n  return new Date(iso).toLocaleTimeString(\"en-IN\", {\n    hour: \"2-digit\", minute: \"2-digit\", second: \"2-digit\",\n  });\n}\n\nexport function FilterBar({ filter, onChange, onSync, syncing, syncedAt }: Props) {\n  const [mounted, setMounted] = useState(false);\n  useEffect(() => setMounted(true), []);\n\n  return (\n    <div className=\"px-5 py-4 border-b border-gray-100 flex flex-wrap gap-3 items-center\">\n      <div className=\"relative flex-1 min-w-[200px]\">\n        <svg className=\"absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n          <circle cx=\"11\" cy=\"11\" r=\"8\"/><path d=\"m21 21-4.35-4.35\"/>\n        </svg>\n        <input\n          type=\"text\"\n          placeholder=\"Search by name, contact, code...\"\n          value={filter.search}\n          onChange={(e) => onChange({ search: e.target.value })}\n          className=\"w-full pl-9 pr-4 py-2 text-sm border border-gray-200 rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n        />\n      </div>\n\n      <input\n        type=\"date\"\n        value={filter.date}\n        onChange={(e) => onChange({ date: e.target.value })}\n        className=\"py-2 px-3 text-sm border border-gray-200 rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-blue-500\"\n      />\n\n      <select\n        value={filter.status}\n        onChange={(e) => onChange({ status: e.target.value as AttendanceStatus | \"\" })}\n        className=\"py-2 px-3 text-sm border border-gray-200 rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-blue-500\"\n      >\n        {STATUS_OPTIONS.map((o) => (\n          <option key={o.value} value={o.value}>{o.label}</option>\n        ))}\n      </select>\n\n      <button\n        onClick={onSync}\n        disabled={syncing}\n        className=\"flex items-center gap-2 px-4 py-2 text-sm font-medium bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-60 disabled:cursor-not-allowed transition-colors\"\n      >\n        <svg\n          className={`w-4 h-4 ${syncing ? \"animate-spin\" : \"\"}`}\n          fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\"\n        >\n          <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15\"/>\n        </svg>\n        {syncing ? \"Syncing...\" : \"Sync Biometric\"}\n      </button>\n\n      {mounted && syncedAt && (\n        <p className=\"text-xs text-gray-400 ml-auto\">\n          Last synced: {formatSyncTime(syncedAt)}\n        </p>\n      )}\n    </div>\n  );\n}\n","import type { AttendanceStatus } from \"@/types/attendance\";\n\nconst CONFIG: Record<\n  AttendanceStatus,\n  { bg: string; text: string; dot: string }\n> = {\n  Present:  { bg: \"bg-green-50\",  text: \"text-green-700\",  dot: \"bg-green-500\"  },\n  Absent:   { bg: \"bg-red-50\",    text: \"text-red-700\",    dot: \"bg-red-500\"    },\n  Late:     { bg: \"bg-amber-50\",  text: \"text-amber-700\",  dot: \"bg-amber-500\"  },\n  \"On Leave\": { bg: \"bg-indigo-50\", text: \"text-indigo-700\", dot: \"bg-indigo-500\" },\n};\n\ninterface Props {\n  status: AttendanceStatus;\n  size?: \"sm\" | \"md\";\n}\n\nexport function StatusBadge({ status, size = \"md\" }: Props) {\n  const cfg = CONFIG[status];\n  const padding = size === \"sm\" ? \"px-2 py-0.5 text-xs\" : \"px-3 py-1 text-xs\";\n\n  return (\n    <span className={`inline-flex items-center gap-1.5 rounded-full font-medium ${cfg.bg} ${cfg.text} ${padding}`}>\n      <span className={`w-1.5 h-1.5 rounded-full ${cfg.dot}`} />\n      {status}\n    </span>\n  );\n}\n","\"use client\";\n\nimport { useState, Fragment } from \"react\";\nimport type { AttendanceRecord } from \"@/types/attendance\";\nimport { StatusBadge } from \"./StatusBadge\";\n\ninterface Props {\n  records: AttendanceRecord[];\n  page: number;\n  totalPages: number;\n  totalFiltered: number;\n  onPageChange: (page: number) => void;\n  onMarkLeave: (studentCode: string) => void;\n  onEdit: (record: AttendanceRecord) => void;\n  onDelete: (record: AttendanceRecord) => void;\n}\n\nfunction getInitials(name: string) {\n  return name.split(\" \").map((w) => w[0]).join(\"\").slice(0, 2).toUpperCase();\n}\n\nexport function AttendanceTable({\n  records,\n  page,\n  totalPages,\n  totalFiltered,\n  onPageChange,\n  onMarkLeave,\n  onEdit,\n  onDelete,\n}: Props) {\n  const [expandedRow, setExpandedRow] = useState<string | null>(null);\n\n  if (records.length === 0) {\n    return (\n      <div className=\"flex flex-col items-center justify-center py-20 text-gray-400\">\n        <svg className=\"w-12 h-12 mb-3 opacity-40\" fill=\"none\" stroke=\"currentColor\" strokeWidth={1.5} viewBox=\"0 0 24 24\">\n          <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m0 12.75h7.5m-7.5 3H12M10.5 2.25H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z\"/>\n        </svg>\n        <p className=\"text-sm font-medium\">No records found</p>\n        <p className=\"text-xs mt-1\">Sync biometric data or adjust filters</p>\n      </div>\n    );\n  }\n\n  return (\n    <>\n      <div className=\"overflow-x-auto\">\n        <table className=\"w-full text-sm\">\n          <thead>\n            <tr className=\"bg-gray-900 text-gray-300\">\n              <th className=\"px-4 py-3 text-left font-medium text-xs w-10\">#</th>\n              <th className=\"px-4 py-3 text-left font-medium text-xs\">Student</th>\n              <th className=\"px-4 py-3 text-left font-medium text-xs\">Contact</th>\n              <th className=\"px-4 py-3 text-left font-medium text-xs\">Punch In</th>\n              <th className=\"px-4 py-3 text-left font-medium text-xs\">Punch Out</th>\n              <th className=\"px-4 py-3 text-left font-medium text-xs\">Device Serial</th>\n              <th className=\"px-4 py-3 text-left font-medium text-xs\">Status</th>\n              <th className=\"px-4 py-3 text-left font-medium text-xs\">Action</th>\n            </tr>\n          </thead>\n          <tbody className=\"divide-y divide-gray-50\">\n            {records.map((record, i) => {\n              const isExpanded = expandedRow === record.student.code;\n              return (\n                <Fragment key={record.student.code}>\n                  <tr\n                    className=\"hover:bg-blue-50/40 transition-colors cursor-pointer\"\n                    onClick={() =>\n                      setExpandedRow(isExpanded ? null : record.student.code)\n                    }\n                  >\n                    {/* # */}\n                    <td className=\"px-4 py-3 text-gray-400 tabular-nums\">\n                      {page * 10 + i + 1}\n                    </td>\n\n                    {/* Student */}\n                    <td className=\"px-4 py-3\">\n                      <div className=\"flex items-center gap-2.5\">\n                        <div className=\"w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center text-xs font-medium flex-shrink-0\">\n                          {getInitials(record.student.name)}\n                        </div>\n                        <div>\n                          <p className=\"font-medium text-gray-900\">{record.student.name}</p>\n                          <p className=\"text-xs text-gray-400\">{record.student.gender} · #{record.student.code}</p>\n                        </div>\n                      </div>\n                    </td>\n\n                    {/* Contact */}\n                    <td className=\"px-4 py-3 text-gray-600 tabular-nums\">\n                      {record.student.contact}\n                    </td>\n\n                    {/* Punch In */}\n                    <td className=\"px-4 py-3 text-gray-600 font-mono text-xs\">\n                      {record.punchIn ?? \"—\"}\n                    </td>\n\n                    {/* Punch Out */}\n                    <td className=\"px-4 py-3 text-gray-600 font-mono text-xs\">\n                      {record.punchOut ?? \"—\"}\n                    </td>\n\n                    {/* Serial */}\n                    <td className=\"px-4 py-3 text-gray-400 font-mono text-xs max-w-[140px] truncate\">\n                      {record.serialNumber}\n                    </td>\n\n                    {/* Status */}\n                    <td className=\"px-4 py-3\" onClick={(e) => e.stopPropagation()}>\n                      <StatusBadge status={record.status} />\n                    </td>\n\n                    {/* Actions */}\n                    <td className=\"px-4 py-3\" onClick={(e) => e.stopPropagation()}>\n                      <div className=\"flex items-center gap-1.5\">\n                        {/* View */}\n                        <button\n                          onClick={() => setExpandedRow(isExpanded ? null : record.student.code)}\n                          className=\"px-2.5 py-1 text-xs rounded-md border border-blue-200 text-blue-600 bg-blue-50 hover:bg-blue-100 transition-colors\"\n                          title=\"View details\"\n                        >\n                          View\n                        </button>\n\n                        {/* Edit */}\n                        <button\n                          onClick={() => onEdit(record)}\n                          className=\"px-2.5 py-1 text-xs rounded-md border border-amber-200 text-amber-700 bg-amber-50 hover:bg-amber-100 transition-colors\"\n                          title=\"Edit record\"\n                        >\n                          <svg className=\"w-3.5 h-3.5 inline-block mr-0.5 -mt-0.5\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n                            <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z\"/>\n                          </svg>\n                          Edit\n                        </button>\n\n                        {/* Delete */}\n                        <button\n                          onClick={() => onDelete(record)}\n                          className=\"px-2.5 py-1 text-xs rounded-md border border-red-200 text-red-600 bg-red-50 hover:bg-red-100 transition-colors\"\n                          title=\"Delete record\"\n                        >\n                          <svg className=\"w-3.5 h-3.5 inline-block mr-0.5 -mt-0.5\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n                            <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16\"/>\n                          </svg>\n                          Delete\n                        </button>\n\n                        {/* Leave (only for Absent) */}\n                        {record.status === \"Absent\" && (\n                          <button\n                            onClick={() => onMarkLeave(record.student.code)}\n                            className=\"px-2.5 py-1 text-xs rounded-md border border-gray-200 text-gray-600 hover:bg-gray-50 transition-colors\"\n                          >\n                            Leave\n                          </button>\n                        )}\n                      </div>\n                    </td>\n                  </tr>\n\n                  {/* Expanded detail row */}\n                  {isExpanded && (\n                    <tr key={`${record.student.code}-detail`} className=\"bg-blue-50/60\">\n                      <td colSpan={8} className=\"px-6 py-4\">\n                        <div className=\"grid grid-cols-2 md:grid-cols-4 gap-4 text-xs\">\n                          <div>\n                            <p className=\"text-gray-400 mb-0.5\">Standard</p>\n                            <p className=\"font-medium text-gray-700\">{record.student.standard ?? \"—\"}</p>\n                          </div>\n                          <div>\n                            <p className=\"text-gray-400 mb-0.5\">Total punches</p>\n                            <p className=\"font-medium text-gray-700\">{record.logCount} log(s)</p>\n                          </div>\n                          {record.temperature != null && (\n                            <div>\n                              <p className=\"text-gray-400 mb-0.5\">Temperature</p>\n                              <p className=\"font-medium text-gray-700\">\n                                {record.temperature}°F\n                                <span className={`ml-1.5 px-1.5 py-0.5 rounded text-xs ${record.temperatureState === \"Normal\" ? \"bg-green-100 text-green-700\" : \"bg-red-100 text-red-700\"}`}>\n                                  {record.temperatureState}\n                                </span>\n                              </p>\n                            </div>\n                          )}\n                          <div>\n                            <p className=\"text-gray-400 mb-0.5\">Date</p>\n                            <p className=\"font-medium text-gray-700\">{record.date}</p>\n                          </div>\n                        </div>\n                      </td>\n                    </tr>\n                  )}\n                </Fragment>\n              );\n            })}\n          </tbody>\n        </table>\n      </div>\n\n      {/* Pagination */}\n      <div className=\"px-5 py-3 border-t border-gray-100 flex items-center justify-between text-sm text-gray-500\">\n        <span>Showing {records.length} of {totalFiltered} records</span>\n        <div className=\"flex items-center gap-2\">\n          <button\n            disabled={page === 0}\n            onClick={() => onPageChange(page - 1)}\n            className=\"px-3 py-1.5 text-xs rounded-md border border-gray-200 disabled:opacity-40 disabled:cursor-not-allowed hover:bg-gray-50 transition-colors\"\n          >\n            ← Prev\n          </button>\n          <span className=\"text-xs px-2\">\n            {page + 1} / {Math.max(totalPages, 1)}\n          </span>\n          <button\n            disabled={page + 1 >= totalPages}\n            onClick={() => onPageChange(page + 1)}\n            className=\"px-3 py-1.5 text-xs rounded-md border border-gray-200 disabled:opacity-40 disabled:cursor-not-allowed hover:bg-gray-50 transition-colors\"\n          >\n            Next →\n          </button>\n        </div>\n      </div>\n    </>\n  );\n}\n","\"use client\";\n\nimport { useState } from \"react\";\nimport type { AttendanceStatus } from \"@/types/attendance\";\nimport type { AddEmployeeData } from \"@/hooks/useAttendance\";\n\ninterface Props {\n  open: boolean;\n  onClose: () => void;\n  onSubmit: (data: AddEmployeeData) => void;\n}\n\nconst statusOptions: AttendanceStatus[] = [\"Present\", \"Absent\", \"Late\", \"On Leave\"];\n\nexport function AddEmployeeModal({ open, onClose, onSubmit }: Props) {\n  const [form, setForm] = useState<AddEmployeeData>({\n    name: \"\",\n    gender: \"Male\",\n    contact: \"\",\n    rollNo: \"\",\n    standard: \"\",\n    status: \"Present\",\n    punchIn: \"\",\n    punchOut: \"\",\n  });\n\n  if (!open) return null;\n\n  const handleSubmit = (e: React.FormEvent) => {\n    e.preventDefault();\n    onSubmit(form);\n    setForm({ name: \"\", gender: \"Male\", contact: \"\", rollNo: \"\", standard: \"\", status: \"Present\", punchIn: \"\", punchOut: \"\" });\n    onClose();\n  };\n\n  const update = (patch: Partial<AddEmployeeData>) =>\n    setForm((prev) => ({ ...prev, ...patch }));\n\n  return (\n    <div className=\"fixed inset-0 z-50 flex items-center justify-center\">\n      {/* Backdrop */}\n      <div\n        className=\"absolute inset-0 bg-black/50 backdrop-blur-sm\"\n        onClick={onClose}\n      />\n\n      {/* Modal */}\n      <div className=\"relative bg-white rounded-2xl shadow-2xl w-full max-w-lg mx-4 overflow-hidden animate-in\">\n        {/* Header */}\n        <div className=\"bg-gray-900 px-6 py-4 flex items-center justify-between\">\n          <h3 className=\"text-white font-medium flex items-center gap-2\">\n            <svg className=\"w-5 h-5\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n              <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z\"/>\n            </svg>\n            Add Employee\n          </h3>\n          <button onClick={onClose} className=\"text-gray-400 hover:text-white transition-colors\">\n            <svg className=\"w-5 h-5\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n              <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M6 18L18 6M6 6l12 12\"/>\n            </svg>\n          </button>\n        </div>\n\n        {/* Form */}\n        <form onSubmit={handleSubmit} className=\"p-6 space-y-4\">\n          {/* Name & Gender */}\n          <div className=\"grid grid-cols-2 gap-4\">\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Full Name *</label>\n              <input\n                required\n                value={form.name}\n                onChange={(e) => update({ name: e.target.value })}\n                placeholder=\"Enter full name\"\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n              />\n            </div>\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Gender *</label>\n              <select\n                required\n                value={form.gender}\n                onChange={(e) => update({ gender: e.target.value })}\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-white\"\n              >\n                <option value=\"Male\">Male</option>\n                <option value=\"Female\">Female</option>\n                <option value=\"Other\">Other</option>\n              </select>\n            </div>\n          </div>\n\n          {/* Contact & Roll No */}\n          <div className=\"grid grid-cols-2 gap-4\">\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Contact *</label>\n              <input\n                required\n                value={form.contact}\n                onChange={(e) => update({ contact: e.target.value })}\n                placeholder=\"Phone number\"\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n              />\n            </div>\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Roll No</label>\n              <input\n                value={form.rollNo}\n                onChange={(e) => update({ rollNo: e.target.value })}\n                placeholder=\"e.g. 16\"\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n              />\n            </div>\n          </div>\n\n          {/* Standard & Status */}\n          <div className=\"grid grid-cols-2 gap-4\">\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Standard / Class</label>\n              <input\n                value={form.standard}\n                onChange={(e) => update({ standard: e.target.value })}\n                placeholder=\"e.g. 10A\"\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n              />\n            </div>\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Status *</label>\n              <select\n                required\n                value={form.status}\n                onChange={(e) => update({ status: e.target.value as AttendanceStatus })}\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-white\"\n              >\n                {statusOptions.map((s) => (\n                  <option key={s} value={s}>{s}</option>\n                ))}\n              </select>\n            </div>\n          </div>\n\n          {/* Punch In & Out */}\n          <div className=\"grid grid-cols-2 gap-4\">\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Punch In</label>\n              <input\n                type=\"time\"\n                step=\"1\"\n                value={form.punchIn}\n                onChange={(e) => update({ punchIn: e.target.value })}\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n              />\n            </div>\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Punch Out</label>\n              <input\n                type=\"time\"\n                step=\"1\"\n                value={form.punchOut}\n                onChange={(e) => update({ punchOut: e.target.value })}\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n              />\n            </div>\n          </div>\n\n          {/* Actions */}\n          <div className=\"flex justify-end gap-3 pt-2\">\n            <button\n              type=\"button\"\n              onClick={onClose}\n              className=\"px-4 py-2 text-sm font-medium text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors\"\n            >\n              Cancel\n            </button>\n            <button\n              type=\"submit\"\n              className=\"px-5 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors flex items-center gap-2\"\n            >\n              <svg className=\"w-4 h-4\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n                <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M12 4v16m8-8H4\"/>\n              </svg>\n              Add Employee\n            </button>\n          </div>\n        </form>\n      </div>\n    </div>\n  );\n}\n","\"use client\";\n\nimport { useState, useEffect } from \"react\";\nimport type { AttendanceStatus, AttendanceRecord } from \"@/types/attendance\";\nimport type { EditRecordData } from \"@/hooks/useAttendance\";\n\ninterface Props {\n  open: boolean;\n  record: AttendanceRecord | null;\n  onClose: () => void;\n  onSubmit: (studentCode: string, data: EditRecordData) => void;\n}\n\nconst statusOptions: AttendanceStatus[] = [\"Present\", \"Absent\", \"Late\", \"On Leave\"];\n\nexport function EditRecordModal({ open, record, onClose, onSubmit }: Props) {\n  const [form, setForm] = useState<EditRecordData>({\n    name: \"\",\n    contact: \"\",\n    status: \"Present\",\n    punchIn: \"\",\n    punchOut: \"\",\n  });\n\n  useEffect(() => {\n    if (record) {\n      setForm({\n        name: record.student.name,\n        contact: record.student.contact,\n        status: record.status,\n        punchIn: record.punchIn ?? \"\",\n        punchOut: record.punchOut ?? \"\",\n      });\n    }\n  }, [record]);\n\n  if (!open || !record) return null;\n\n  const handleSubmit = (e: React.FormEvent) => {\n    e.preventDefault();\n    onSubmit(record.student.code, form);\n    onClose();\n  };\n\n  const update = (patch: Partial<EditRecordData>) =>\n    setForm((prev) => ({ ...prev, ...patch }));\n\n  return (\n    <div className=\"fixed inset-0 z-50 flex items-center justify-center\">\n      {/* Backdrop */}\n      <div\n        className=\"absolute inset-0 bg-black/50 backdrop-blur-sm\"\n        onClick={onClose}\n      />\n\n      {/* Modal */}\n      <div className=\"relative bg-white rounded-2xl shadow-2xl w-full max-w-lg mx-4 overflow-hidden animate-in\">\n        {/* Header */}\n        <div className=\"bg-gray-900 px-6 py-4 flex items-center justify-between\">\n          <h3 className=\"text-white font-medium flex items-center gap-2\">\n            <svg className=\"w-5 h-5\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n              <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z\" />\n            </svg>\n            Edit Record — {record.student.code}\n          </h3>\n          <button onClick={onClose} className=\"text-gray-400 hover:text-white transition-colors\">\n            <svg className=\"w-5 h-5\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n              <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M6 18L18 6M6 6l12 12\" />\n            </svg>\n          </button>\n        </div>\n\n        {/* Form */}\n        <form onSubmit={handleSubmit} className=\"p-6 space-y-4\">\n          {/* Name & Contact */}\n          <div className=\"grid grid-cols-2 gap-4\">\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Full Name *</label>\n              <input\n                required\n                value={form.name}\n                onChange={(e) => update({ name: e.target.value })}\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n              />\n            </div>\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Contact *</label>\n              <input\n                required\n                value={form.contact}\n                onChange={(e) => update({ contact: e.target.value })}\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n              />\n            </div>\n          </div>\n\n          {/* Status */}\n          <div>\n            <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Status *</label>\n            <select\n              required\n              value={form.status}\n              onChange={(e) => update({ status: e.target.value as AttendanceStatus })}\n              className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-white\"\n            >\n              {statusOptions.map((s) => (\n                <option key={s} value={s}>{s}</option>\n              ))}\n            </select>\n          </div>\n\n          {/* Punch In & Out */}\n          <div className=\"grid grid-cols-2 gap-4\">\n            <div>\n              <label className=\"block text-xs font-medium text-gray-500 mb-1.5\">Punch In</label>\n              <input\n                type=\"time\"\n                step=\"1\"\n                value={form.punchIn}\n                onChange={(e) => update({ punchIn: e.target.value })}\n                className=\"w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent\"\n              />\n            </div>\n       