 Employee <strong>{record.student.name}</strong> ({record.student.code}) will be permanently removed. This action cannot be undone.\n              </p>\n            </div>\n          </div>\n\n          {/* Actions */}\n          <div className=\"flex justify-end gap-3 mt-6\">\n            <button\n              onClick={onClose}\n              className=\"px-4 py-2 text-sm font-medium text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors\"\n            >\n              Cancel\n            </button>\n            <button\n              onClick={() => {\n                onConfirm(record.student.code);\n                onClose();\n              }}\n              className=\"px-5 py-2 text-sm font-medium text-white bg-red-600 rounded-lg hover:bg-red-700 transition-colors flex items-center gap-2\"\n            >\n              <svg className=\"w-4 h-4\" fill=\"none\" stroke=\"currentColor\" strokeWidth={2} viewBox=\"0 0 24 24\">\n                <path strokeLinecap=\"round\" strokeLinejoin=\"round\" d=\"M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16\"/>\n              </svg>\n              Delete\n            </button>\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}\n"],"names":["today","Date","toISOString","split","defaultFilter","search","status","date","staticRecords","student","id","code","name","gender","contact","rollNo","standard","punchIn","punchOut","serialNumber","temperature","temperatureState","logCount","nextId","computeSummary","recs","total","length","present","filter","r","absent","late","onLeave","useAttendance","records","setRecords","setFilter","syncing","syncedAt","error","page","setPage","PER_PAGE","sync","_date","markLeave","studentCode","prev","map","addEmployee","data","String","padStart","newRecord","editRecord","deleteRecord","updateFilter","patch","filtered","q","toLowerCase","matchSearch","includes","matchStatus","filteredSumma